Inside a jail, programs that use pthread (libthr) get stuck in umtxn state. This problem exhibited itself since upgrading to 10.2-RELEASE-p5 with freebsd-update.

Mitigations tried:

- Updated poudriere jail and rebuilt all packages
- Reinstalled all packages inside jail with pkg upgrade -f

Test program:

---- CUT HERE ----
#include <unistd.h>
#include <sys/types.h>
#include <errno.h>
#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <string.h>

void  message(void *ptr);

typedef struct stdata {
  int  id;
  char  msg[100];
}  stdata;

int
main()
{
  pthread_t t1, t2;
  stdata d1, d2;

  d1.id = 1;
  strcpy(d1.msg, "Thread 1");

  d2.id = 2;
  strcpy(d2.msg, "Thread 2");

  pthread_create(&t1, NULL, (void *)&message, (void *)&d1);
  pthread_create(&t2, NULL, (void *)&message, (void *)&d2);

  pthread_join(t1, NULL);
  pthread_join(t2, NULL);

  exit(0);
}

void
message(void *ptr)
{
  stdata *data;

  data = (stdata *) ptr;

  printf("Thread %d message %s \n", data->id, data->msg);

  pthread_exit(0);
}
